--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -170,6 +170,99 @@
   '  OBBBOBBBO     ',
 ];

+// Idle animation frames for each character type
+// Each array contains 4 frames with subtle vertical breathing offset,
+// blinking frame (eye color change), and role-specific idle motions.
+
+const KING_IDLE_FRAMES = [
+  KING_SPRITE,
+  KING_SPRITE.map(line => line), // breathing offset applied in drawCharacter
+  KING_SPRITE.map(line => line.replace('O', '0')), // blinking eyes (replace 'O' with '0' for eyes)
+  KING_SPRITE,
+];
+
+const KNIGHT_IDLE_FRAMES = [
+  KNIGHT_SPRITE,
+  KNIGHT_SPRITE.map(line => line), // breathing offset applied in drawCharacter
+  KNIGHT_SPRITE.map(line => line.replace('O', '0')), // blinking eyes
+  // sword sway: shift sword pixels one char right and left in frames 3 and 4
+  KNIGHT_SPRITE.map((line, i) => {
+    if (i >= 6 && i <= 8) {
+      // shift sword pixels right by 1 (replace 'P' with ' ' at pos 5, add 'P' at pos 6)
+      return line.substring(0,5) + ' ' + line[5] + line.substring(6);
+    }
+    return line;
+  }),
+];
+
+const HEALER_IDLE_FRAMES = [
+  HEALER_SPRITE,
+  HEALER_SPRITE.map(line => line),
+  HEALER_SPRITE.map(line => line.replace('O', '0')),
+  HEALER_SPRITE,
+];
+
+const SENTINEL_IDLE_FRAMES = [
+  SENTINEL_SPRITE,
+  SENTINEL_SPRITE.map(line => line),
+  SENTINEL_SPRITE.map(line => line.replace('O', '0')),
+  SENTINEL_SPRITE,
+];
+
+const NOBILITY_IDLE_FRAMES = [
+  NOBILITY_SPRITE,
+  NOBILITY_SPRITE.map(line => line),
+  NOBILITY_SPRITE.map(line => line.replace('O', '0')),
+  NOBILITY_SPRITE,
+];
+
+const SQUIRE_IDLE_FRAMES = [
+  SQUIRE_SPRITE,
+  SQUIRE_SPRITE.map(line => line),
+  SQUIRE_SPRITE.map(line => line.replace('O', '0')),
+  SQUIRE_SPRITE,
+];
+
+const SCRIBE_IDLE_FRAMES = [
+  SCRIBE_SPRITE,
+  SCRIBE_SPRITE.map(line => line),
+  SCRIBE_SPRITE.map(line => line.replace('O', '0')),
+  // page turn: simulate by toggling 'T' to 't' in frame 4
+  SCRIBE_SPRITE.map(line => line.replace(/T/g, 't')),
+];
+
+const JUDGE_IDLE_FRAMES = [
+  JUDGE_SPRITE,
+  JUDGE_SPRITE.map(line => line),
+  JUDGE_SPRITE.map(line => line.replace('O', '0')),
+  JUDGE_SPRITE,
+];
+
+const BLACKSMITH_IDLE_FRAMES = [
+  BLACKSMITH_SPRITE,
+  BLACKSMITH_SPRITE.map(line => line),
+  BLACKSMITH_SPRITE.map(line => line.replace('O', '0')),
+  // hammer sway: shift 'M' chars left and right in frame 4
+  BLACKSMITH_SPRITE.map((line, i) => {
+    if (i === 8 || i === 9) {
+      return line.substring(0,4) + line[5] + 'M' + line.substring(7);
+    }
+    return line;
+  }),
+];
+
+const IDLE_FRAMES_MAP: Record<CharacterType, string[][]> = {
+  king: KING_IDLE_FRAMES,
+  knight: KNIGHT_IDLE_FRAMES,
+  healer: HEALER_IDLE_FRAMES,
+  sentinel: SENTINEL_IDLE_FRAMES,
+  nobility: NOBILITY_IDLE_FRAMES,
+  squire: SQUIRE_IDLE_FRAMES,
+  scribe: SCRIBE_IDLE_FRAMES,
+  judge: JUDGE_IDLE_FRAMES,
+  blacksmith: BLACKSMITH_IDLE_FRAMES,
+};
+
+// Frame duration in milliseconds
+const IDLE_FRAME_DURATION = 200;
+
+// ─── Drawing engine ────────────────────────────────────────────────
+
+function drawSpriteDef(
+  ctx: CanvasRenderingContext2D,
+  sprite: string[],
+  palette: Record<string, string>,
+  x: number, y: number, s: number,
+  flipH = false,
+  yOffset = 0,
+) {
+  // yOffset allows vertical breathing offset
+  y += yOffset;
+  // existing drawing logic unchanged
+  for (let row = 0; row < sprite.length; row++) {
+    const line = sprite[row];
+    for (let col = 0; col < line.length; col++) {
+      const c = line[col];
+      if (c === ' ') continue;
+      const color = palette[c] || '#000000';
+      ctx.fillStyle = color;
+      const drawX = flipH ? x + (line.length - 1 - col) * s : x + col * s;
+      ctx.fillRect(drawX, y + row * s, s, s);
+    }
+  }
+}
+
+// Modified drawCharacter to accept frame parameter and handle idle animation
+function drawCharacter(
+  ctx: CanvasRenderingContext2D,
+  characterType: CharacterType,
+  x: number,
+  y: number,
+  scale: number,
+  frame: number,
+) {
+  const frames = IDLE_FRAMES_MAP[characterType] || [SPRITE_MAP[characterType]];
+  const frameIndex = frame % frames.length;
+  const sprite = frames[frameIndex];
+  const palette = PALETTE_MAP[characterType];
+
+  // Calculate breathing vertical offset: subtle sine wave based on frame
+  // breathing offset cycles every 4 frames: 0, +1, 0, -1 pixels
+  const breathingOffsets = [0, 1, 0, -1];
+  const yOffset = breathingOffsets[frameIndex] || 0;
+
+  drawSpriteDef(ctx, sprite, palette, x, y + yOffset, scale);
+}
+
+// Animation frame counter helper
+function getIdleAnimationFrame(timestamp: number): number {
+  return Math.floor(timestamp / IDLE_FRAME_DURATION) % 4;
+}
+
